pub trait TRemoteAgentServiceSyncClient {
  fn get_agent_info(&mut self) -> thrift::Result<AgentInfo>;
  fn get_workspace_path(&mut self) -> thrift::Result<String>;
  fn start_process(&mut self, command: String, args: Vec<String>, working_directory: String, environment: BTreeMap<String, String>) -> thrift::Result<ProcessInfo>;
  fn kill_process(&mut self, pid: i64, force: bool) -> thrift::Result<bool>;
  fn is_process_alive(&mut self, pid: i64) -> thrift::Result<bool>;
  fn list_processes(&mut self) -> thrift::Result<Vec<ProcessInfo>>;
  fn read_process_output(&mut self, pid: i64) -> thrift::Result<ProcessOutput>;
  fn read_file(&mut self, path: String) -> thrift::Result<Vec<u8>>;
  fn write_file(&mut self, path: String, data: Vec<u8>) -> thrift::Result<()>;
  fn delete_file(&mut self, path: String) -> thrift::Result<bool>;
  fn list_directory(&mut self, path: String) -> thrift::Result<Vec<FileInfo>>;
  fn file_exists(&mut self, path: String) -> thrift::Result<bool>;
  fn create_directory(&mut self, path: String, recursive: bool) -> thrift::Result<()>;
  fn list_roots(&mut self) -> thrift::Result<Vec<FileInfo>>;
  fn set_permissions(&mut self, path: String, mode: i32) -> thrift::Result<bool>;
  fn begin_upload(&mut self, path: String, file_size: i64) -> thrift::Result<String>;
  fn upload_chunk(&mut self, transfer_id: String, data: Vec<u8>) -> thrift::Result<()>;
  fn finish_upload(&mut self, transfer_id: String) -> thrift::Result<()>;
  fn cancel_upload(&mut self, transfer_id: String) -> thrift::Result<()>;
  fn begin_download(&mut self, path: String) -> thrift::Result<DownloadInfo>;
  fn download_chunk(&mut self, transfer_id: String, chunk_size: i32) -> thrift::Result<Vec<u8>>;
  fn finish_download(&mut self, transfer_id: String) -> thrift::Result<()>;
  fn get_env_variable(&mut self, name: String) -> thrift::Result<String>;
  fn get_env_variables(&mut self) -> thrift::Result<BTreeMap<String, String>>;
  fn get_system_info(&mut self) -> thrift::Result<SystemInfo>;
  fn get_user_info(&mut self) -> thrift::Result<UserInfo>;
}

